(function(){'use strict';if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initialize)}else{initialize()}
function initialize(){setupNavigation();setupAccordions();setupForms();setupLazyLoading();setupScrollEffects();setupModals();enhanceAccessibility();setupResponsiveBehavior()}
function setupNavigation(){const navToggle=document.querySelector('.navbar__toggle');const navMenu=document.querySelector('.navbar__menu');const dropdownButtons=document.querySelectorAll('.navbar__button[aria-haspopup="true"]');if(navToggle&&navMenu){navToggle.addEventListener('click',function(){const expanded=this.getAttribute('aria-expanded')==='true'||!1;this.setAttribute('aria-expanded',!expanded);this.classList.toggle('active');navMenu.classList.toggle('open');if(!expanded){document.body.classList.add('mobile-menu-open')}else{document.body.classList.remove('mobile-menu-open')}})}
if(dropdownButtons.length){dropdownButtons.forEach(button=>{button.addEventListener('click',function(e){e.preventDefault();const expanded=this.getAttribute('aria-expanded')==='true'||!1;const controlsId=this.getAttribute('aria-controls');const menu=controlsId?document.getElementById(controlsId):null;closeAllDropdowns(button);if(menu){this.setAttribute('aria-expanded',!expanded);menu.classList.toggle('is-visible');menu.setAttribute('aria-hidden',expanded);if(!expanded&&!menu.classList.contains('is-loaded')){loadMegaMenuContent(button,menu)}}})});document.addEventListener('click',function(e){if(!e.target.closest('.navbar__item.has-megamenu')&&!e.target.closest('.megamenu')){closeAllDropdowns()}});document.addEventListener('keydown',function(e){if(e.key==='Escape'){closeAllDropdowns();const activeButton=document.querySelector('.navbar__button[aria-expanded="true"]');if(activeButton){activeButton.focus()}}})}
function closeAllDropdowns(except=null){dropdownButtons.forEach(btn=>{if(btn!==except){btn.setAttribute('aria-expanded','false');const controlsId=btn.getAttribute('aria-controls');const menu=controlsId?document.getElementById(controlsId):null;if(menu){menu.classList.remove('is-visible');menu.setAttribute('aria-hidden','true')}}})}
function loadMegaMenuContent(button,menu){const item=button.closest('.navbar__item');if(!item)return;const menuType=item.getAttribute('data-menu-type');if(!menuType)return;const template=document.getElementById(`template-${menuType}`);if(template){menu.innerHTML=template.innerHTML;menu.classList.add('is-loaded')}}
const isDesktop=window.matchMedia('(min-width: 992px)').matches;const hasHoverSupport=window.matchMedia('(hover: hover)').matches;if(isDesktop&&hasHoverSupport){const menuItems=document.querySelectorAll('.navbar__item.has-megamenu');menuItems.forEach(item=>{let hoverTimeout;item.addEventListener('mouseenter',function(){clearTimeout(hoverTimeout);closeAllDropdowns(item.querySelector('.navbar__button'));const button=item.querySelector('.navbar__button');if(button){button.setAttribute('aria-expanded','true');const controlsId=button.getAttribute('aria-controls');const menu=controlsId?document.getElementById(controlsId):null;if(menu){if(!menu.classList.contains('is-loaded')){loadMegaMenuContent(button,menu)}
menu.classList.add('is-visible');menu.setAttribute('aria-hidden','false')}}});item.addEventListener('mouseleave',function(){hoverTimeout=setTimeout(()=>{const button=item.querySelector('.navbar__button');if(button){button.setAttribute('aria-expanded','false');const controlsId=button.getAttribute('aria-controls');const menu=controlsId?document.getElementById(controlsId):null;if(menu){menu.classList.remove('is-visible');menu.setAttribute('aria-hidden','true')}}},150)})})}}
function setupAccordions(){const accordions=document.querySelectorAll('[data-bs-toggle="collapse"]');if(accordions.length){if(window.location.hash){const targetId=window.location.hash.substring(1);const targetAccordion=document.getElementById(targetId);if(targetAccordion&&targetAccordion.classList.contains('collapse')){const controlButton=document.querySelector(`[data-bs-target="#${targetId}"]`);if(controlButton){setTimeout(()=>{controlButton.click();targetAccordion.scrollIntoView({behavior:'smooth',block:'start'})},300)}}}
accordions.forEach(btn=>{btn.addEventListener('keydown',function(e){const buttons=Array.from(accordions);const currentIndex=buttons.indexOf(this);let targetIndex;switch(e.key){case 'ArrowUp':e.preventDefault();targetIndex=currentIndex>0?currentIndex-1:buttons.length-1;buttons[targetIndex].focus();break;case 'ArrowDown':e.preventDefault();targetIndex=currentIndex<buttons.length-1?currentIndex+1:0;buttons[targetIndex].focus();break;case 'Home':e.preventDefault();buttons[0].focus();break;case 'End':e.preventDefault();buttons[buttons.length-1].focus();break}})})}}
function setupForms(){const forms=document.querySelectorAll('form');forms.forEach(form=>{const inputs=form.querySelectorAll('input, select, textarea');inputs.forEach(input=>{input.addEventListener('blur',function(){validateInput(this)});if(input.type==='text'||input.type==='email'||input.type==='tel'){input.addEventListener('input',function(){this.classList.remove('is-invalid')})}});form.addEventListener('submit',function(e){let isValid=!0;inputs.forEach(input=>{if(!validateInput(input)){isValid=!1}});if(!isValid){e.preventDefault();const firstInvalid=form.querySelector('.is-invalid');if(firstInvalid){firstInvalid.focus()}}})});function validateInput(input){let isValid=!0;const errorMessage=input.dataset.errorMessage||'Please check this field.';if(input.disabled||input.readOnly){return!0}
if(input.hasAttribute('required')&&!input.value.trim()){isValid=!1}
if(input.pattern&&input.value){const pattern=new RegExp(input.pattern);if(!pattern.test(input.value)){isValid=!1}}
switch(input.type){case 'email':if(input.value&&!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(input.value)){isValid=!1}
break;case 'tel':if(input.value&&!/^[\d\s()+-.]+$/.test(input.value)){isValid=!1}
break}
if(isValid){input.classList.remove('is-invalid');input.classList.add('is-valid');const errorEl=input.nextElementSibling;if(errorEl&&errorEl.classList.contains('invalid-feedback')){errorEl.textContent=''}}else{input.classList.remove('is-valid');input.classList.add('is-invalid');let errorEl=input.nextElementSibling;if(!errorEl||!errorEl.classList.contains('invalid-feedback')){errorEl=document.createElement('div');errorEl.className='invalid-feedback';input.parentNode.insertBefore(errorEl,input.nextSibling)}
errorEl.textContent=errorMessage}
return isValid}}
function setupLazyLoading(){const lazyImages=document.querySelectorAll('img[loading="lazy"], iframe[loading="lazy"]');if('loading' in HTMLImageElement.prototype===!1&&'IntersectionObserver' in window){const lazyImageObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){const lazyImage=entry.target;if(lazyImage.dataset.src){lazyImage.src=lazyImage.dataset.src}
if(lazyImage.dataset.srcset){lazyImage.srcset=lazyImage.dataset.srcset}
lazyImage.classList.remove('lazy');lazyImageObserver.unobserve(lazyImage)}})},{rootMargin:'200px 0px'});lazyImages.forEach(image=>{if(!('loading' in image)){lazyImageObserver.observe(image)}})}}
function setupScrollEffects(){if(window.matchMedia('(prefers-reduced-motion: no-preference)').matches){const scrollElements=document.querySelectorAll('.animate-on-scroll');if(scrollElements.length&&'IntersectionObserver' in window){const scrollObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('in-view');scrollObserver.unobserve(entry.target)}})},{rootMargin:'0px 0px -100px 0px'});scrollElements.forEach(element=>{scrollObserver.observe(element)})}
const parallaxElements=document.querySelectorAll('.parallax');if(parallaxElements.length){window.addEventListener('scroll',throttle(function(){const scrollY=window.pageYOffset;parallaxElements.forEach(element=>{const speed=element.dataset.speed||0.5;element.style.transform=`translateY(${scrollY * speed}px)`})},20))}}
function throttle(func,limit){let inThrottle;return function(){const args=arguments;const context=this;if(!inThrottle){func.apply(context,args);inThrottle=!0;setTimeout(()=>inThrottle=!1,limit)}}}}
function setupModals(){const modals=document.querySelectorAll('.modal');const modalTriggers=document.querySelectorAll('[data-bs-toggle="modal"]');if(modals.length&&modalTriggers.length){modalTriggers.forEach(trigger=>{trigger.addEventListener('click',function(e){e.preventDefault();const targetId=this.getAttribute('data-bs-target')||this.getAttribute('href');if(!targetId)return;const modal=document.querySelector(targetId);if(!modal)return;openModal(modal)})});const closeButtons=document.querySelectorAll('[data-bs-dismiss="modal"]');closeButtons.forEach(button=>{button.addEventListener('click',function(){const modal=this.closest('.modal');if(modal){closeModal(modal)}})});modals.forEach(modal=>{modal.addEventListener('click',function(e){if(e.target===this){closeModal(this)}})});document.addEventListener('keydown',function(e){if(e.key==='Escape'){const openModal=document.querySelector('.modal.show');if(openModal){closeModal(openModal)}}})}
function openModal(modal){modal.style.display='block';setTimeout(()=>{modal.classList.add('show')},10);document.body.classList.add('modal-open');const focusable=modal.querySelectorAll('button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])');if(focusable.length){focusable[0].focus()}
modal.addEventListener('keydown',trapFocus)}
function closeModal(modal){modal.classList.remove('show');setTimeout(()=>{modal.style.display='none';document.body.classList.remove('modal-open')},300);modal.removeEventListener('keydown',trapFocus);const triggerId=modal.dataset.trigger;if(triggerId){const trigger=document.getElementById(triggerId);if(trigger){trigger.focus()}}}
function trapFocus(e){if(e.key!=='Tab')return;const focusable=this.querySelectorAll('button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])');const firstFocusable=focusable[0];const lastFocusable=focusable[focusable.length-1];if(e.shiftKey&&document.activeElement===firstFocusable){e.preventDefault();lastFocusable.focus()}else if(!e.shiftKey&&document.activeElement===lastFocusable){e.preventDefault();firstFocusable.focus()}}}
function enhanceAccessibility(){const skipLink=document.querySelector('.skip-link');if(skipLink){skipLink.addEventListener('click',function(e){e.preventDefault();const targetId=this.getAttribute('href');const target=document.querySelector(targetId);if(target){target.setAttribute('tabindex','-1');target.focus();target.addEventListener('blur',function(){target.removeAttribute('tabindex')},{once:!0})}})}
const buttons=document.querySelectorAll('button');buttons.forEach(button=>{if(!button.textContent.trim()&&!button.getAttribute('aria-label')){const icon=button.querySelector('i, .icon');if(icon&&icon.classList){let iconClass=Array.from(icon.classList).find(cls=>cls.includes('fa-'));if(iconClass){iconClass=iconClass.replace('fa-','').replace(/-/g,' ');button.setAttribute('aria-label',iconClass)}}}});const inputs=document.querySelectorAll('input, select, textarea');inputs.forEach(input=>{if(!input.id)return;const label=document.querySelector(`label[for="${input.id}"]`);if(!label){const wrapper=input.parentElement;const placeholderText=input.getAttribute('placeholder');if(placeholderText&&wrapper){const newLabel=document.createElement('label');newLabel.setAttribute('for',input.id);newLabel.className='form-label';newLabel.textContent=placeholderText;wrapper.insertBefore(newLabel,input)}}})}
function setupResponsiveBehavior(){let resizeTimer;const resizeHandler=function(){clearTimeout(resizeTimer);resizeTimer=setTimeout(function(){const wasMobile=document.body.classList.contains('mobile-view');const isMobile=window.innerWidth<992;if(wasMobile!==isMobile){document.body.classList.toggle('mobile-view',isMobile);document.body.classList.toggle('desktop-view',!isMobile);if(!isMobile){const navMenu=document.querySelector('.navbar__menu');const navToggle=document.querySelector('.navbar__toggle');if(navMenu&&navMenu.classList.contains('open')){navMenu.classList.remove('open');document.body.classList.remove('mobile-menu-open');if(navToggle){navToggle.classList.remove('active');navToggle.setAttribute('aria-expanded','false')}}}}},250)};const isMobile=window.innerWidth<992;document.body.classList.toggle('mobile-view',isMobile);document.body.classList.toggle('desktop-view',!isMobile);window.addEventListener('resize',resizeHandler)}})()